//! Inspect generated OnPair benchmark `.vortex` files and report which layout
//! nodes own the file segments.

#![expect(clippy::print_stdout)]

use std::collections::BTreeMap;
use std::path::Path;
use std::path::PathBuf;

use anyhow::Result;
use clap::Parser;
use serde::Serialize;
use vortex::file::OpenOptionsSessionExt;
use vortex::file::SegmentSpec;
use vortex::layout::LayoutRef;
use vortex_bench::SESSION;

#[derive(Parser)]
struct Args {
    /// Root generated by `benchmarks/onpair-bench/run.py`.
    #[arg(long, default_value = "vortex-bench/data/onpair-bench")]
    root: PathBuf,
    /// Dataset id to inspect.
    #[arg(long, default_value = "dbtext")]
    dataset: String,
    /// Optional column filter.
    #[arg(long)]
    column: Option<String>,
}

#[derive(Debug, Serialize)]
struct Row {
    dataset: String,
    column: String,
    config: String,
    file: String,
    file_bytes: u64,
    segment_bytes: u64,
    unassigned_bytes: u64,
    path: String,
    bytes: u64,
}

#[tokio::main]
async fn main() -> Result<()> {
    let args = Args::parse();
    let dataset_root = args.root.join(&args.dataset);
    let mut rows = Vec::new();

    for column_dir in sorted_dirs(&dataset_root)? {
        let column = file_name(&column_dir);
        if args
            .column
            .as_deref()
            .is_some_and(|filter| filter != column)
        {
            continue;
        }

        for config_dir in sorted_dirs(&column_dir)? {
            let config = file_name(&config_dir).to_string();
            for file in sorted_vortex_files(&config_dir)? {
                inspect_file(&args.dataset, column, &config, &file, &mut rows).await?;
            }
        }
    }

    println!("{}", serde_json::to_string_pretty(&rows)?);
    Ok(())
}

async fn inspect_file(
    dataset: &str,
    column: &str,
    config: &str,
    file: &Path,
    rows: &mut Vec<Row>,
) -> Result<()> {
    let file_bytes = std::fs::metadata(file)?.len();
    let vxf = SESSION.open_options().open_path(file.to_path_buf()).await?;
    let footer = vxf.footer();
    let segments = footer.segment_map();
    let segment_bytes = segments.iter().map(|s| u64::from(s.length)).sum::<u64>();
    let mut by_path = BTreeMap::<String, u64>::new();
    collect_layout_bytes(footer.layout(), segments, "$".to_string(), &mut by_path)?;

    let file_name = file
        .file_name()
        .and_then(|s| s.to_str())
        .unwrap_or_default()
        .to_string();
    let unassigned_bytes = file_bytes.saturating_sub(segment_bytes);
    for (path, bytes) in by_path {
        rows.push(Row {
            dataset: dataset.to_string(),
            column: column.to_string(),
            config: config.to_string(),
            file: file_name.clone(),
            file_bytes,
            segment_bytes,
            unassigned_bytes,
            path,
            bytes,
        });
    }
    Ok(())
}

fn collect_layout_bytes(
    layout: &LayoutRef,
    segments: &[SegmentSpec],
    path: String,
    by_path: &mut BTreeMap<String, u64>,
) -> Result<()> {
    let own_bytes = layout
        .segment_ids()
        .into_iter()
        .map(|seg_id| u64::from(segments[*seg_id as usize].length))
        .sum::<u64>();
    if own_bytes > 0 {
        *by_path.entry(path.clone()).or_default() += own_bytes;
    }

    for idx in 0..layout.nchildren() {
        let child_type = layout.child_type(idx);
        let child = layout.child(idx)?;
        let child_path = format!(
            "{path}/{}:{}",
            child_type.name(),
            child.encoding_id().as_ref()
        );
        collect_layout_bytes(&child, segments, child_path, by_path)?;
    }
    Ok(())
}

fn sorted_dirs(path: &Path) -> Result<Vec<PathBuf>> {
    let mut dirs = std::fs::read_dir(path)?
        .filter_map(|entry| entry.ok().map(|e| e.path()))
        .filter(|path| path.is_dir())
        .collect::<Vec<_>>();
    dirs.sort();
    Ok(dirs)
}

fn sorted_vortex_files(path: &Path) -> Result<Vec<PathBuf>> {
    let mut files = std::fs::read_dir(path)?
        .filter_map(|entry| entry.ok().map(|e| e.path()))
        .filter(|path| path.extension().is_some_and(|ext| ext == "vortex"))
        .collect::<Vec<_>>();
    files.sort();
    Ok(files)
}

fn file_name(path: &Path) -> &str {
    path.file_name()
        .and_then(|s| s.to_str())
        .unwrap_or_default()
}
